+    pub fn arange(
+        &mut self,
+        start: f64,
+        end: f64,
+        step: f64,
+        requires_grad: bool,
+    ) -> Result<TensorNodeId, AutogradError> {
+        let mut values = Vec::new();
+        let mut current = start;
+        if step > 0.0 {
+            while current < end {
+                values.push(current);
+                current += step;
+            }
+        } else if step < 0.0 {
+            while current > end {
+                values.push(current);
+                current += step;
+            }
+        }
+        let n = values.len();
+        self.tensor_tape.leaf(values, vec![n], requires_grad)
+    }
